from langchain_anthropic import ChatAnthropic
from langchain_core.messages import SystemMessage, HumanMessage

persona_llm = ChatAnthropic(model="claude-haiku-4-5-20251001")

def format_transcript(transcript: list[SimMessage], last_n: int = 6) -> str:
    """Format the most recent N turns of the transcript."""    recent = transcript[-last_n:] if len(transcript) > last_n else transcript
    if not recent:
        return "(conversation just started)"
    return "\n".join(f"[{m.persona}]: {m.content}" for m in recent)

def make_persona_agent(persona: Persona):
    """Creates a node that speaks as the given persona."""
    def persona_node(state: SimulationState) -> dict:
        if state["current_speaker"] != persona.name:
            return {}   # not our turn

        concerns_text = ", ".join(persona.concerns)
        system = f"""You are {persona.name}, the {persona.role}.
Your concerns: {concerns_text}.
Tone: {persona.tone}.
Context: {persona.knowledge}

Stay in character. Respond to what was just said. Be concise (2-4 sentences).
Do NOT break character or speak as yourself."""
        history = format_transcript(state["transcript"])
        prompt = f"""Scenario: {state['scenario']}

Conversation so far:
{history}

As {persona.name}, what do you say next? Respond in character."""
        response = persona_llm.invoke([
            SystemMessage(content=system),
            HumanMessage(content=prompt)
        ])

        msg = SimMessage(
            persona=persona.name,
            content=response.content,
            turn=state["turn"],
        )
        return {"transcript": [msg]}

    persona_node.__name__ = f"persona_{persona.name}"
    return persona_node

director_llm = ChatAnthropic(model="claude-haiku-4-5-20251001")

def rule_based_director(state: SimulationState) -> dict:
    """Cycles through personas in fixed order."""    persona_names = list(state["personas"].keys())
    next_idx = (state["turn"] + 1) % len(persona_names)
    next_speaker = persona_names[next_idx]
    next_turn = state["turn"] + 1
    done = next_turn >= state["max_turns"]
    return {
        "current_speaker": next_speaker,
        "turn": next_turn,
        "done": done,
    }

def llm_director(state: SimulationState) -> dict:
    """LLM-driven director: picks the most natural next speaker."""    if state["turn"] >= state["max_turns"]:
        return {"done": True, "turn": state["turn"] + 1}

    history = format_transcript(state["transcript"])
    personas_desc = ", ".join(
        f"{name} ({p.role})" for name, p in state["personas"].items()
    )
    prompt = f"""Scenario: {state['scenario']}
Participants: {personas_desc}

Recent conversation:
{history}

Who should speak next? Choose one participant name exactly.
Consider: who was addressed? who hasn't spoken recently? whose concerns are most relevant now?"""
    response = director_llm.invoke([
        SystemMessage(content="You are a simulation director. Select the most natural next speaker."),
        HumanMessage(content=prompt)
    ])

    chosen = response.content.strip()
    # Validate against known personas
    if chosen not in state["personas"]:
        # Fallback: cycle
        names = list(state["personas"].keys())
        chosen = names[state["turn"] % len(names)]

    return {
        "current_speaker": chosen,
        "turn": state["turn"] + 1,
        "done": state["turn"] + 1 >= state["max_turns"],
    }

debrief_llm = ChatAnthropic(model="claude-sonnet-5")

def debrief_node(state: SimulationState) -> dict:
    """Reads the full transcript and produces a structured debrief."""    full_transcript = "\n".join(
        f"[Turn {m.turn}] {m.persona}: {m.content}" for m in state["transcript"]
    )
    personas_desc = "\n".join(
        f"- {name} ({p.role}): cares about {', '.join(p.concerns)}"
        for name, p in state["personas"].items()
    )

    prompt = f"""Scenario: {state['scenario']}

Participants:
{personas_desc}

Full simulation transcript:
{full_transcript}

Produce a structured debrief:
1. Key points of agreement across all personas
2. Main objections or concerns raised (by whom)
3. Unresolved tensions
4. Recommended next steps based on the discussion"""
    response = debrief_llm.invoke([
        SystemMessage(content="You are a neutral analyst debriefing a stakeholder simulation."),
        HumanMessage(content=prompt)
    ])

    return {"summary": response.content, "done": True}
